mapper.select:
SELECT a.id, u.id AS staff, u.name AS staffName, u.avatar AS staffAvatar, u.create_time AS staffRegisterTime, a.create_time, CASE a.type WHEN '1' THEN '签到' WHEN '2' THEN '请假' END AS type, CASE a.overtime WHEN '1' THEN '是' WHEN '2' THEN '否' END AS overtime FROM attendance a LEFT JOIN sys_user u ON a.staff = u.id
a.create_time >= DATE_FORMAT(NOW(), '%Y-%m-01') AND a.create_time < DATE_ADD(DATE_FORMAT(NOW(), '%Y-%m-01'), INTERVAL 1 MONTH)
AND a.type = #{attendanceDTO.type}
AND u.name LIKE CONCAT('%', #{attendanceDTO.staffName}, '%')
AND a.overtime = #{attendanceDTO.overtime}
AND a.staff = #{attendanceDTO.staff}
AND DATE_FORMAT(a.create_time, '%Y-%m') >= #{attendanceDTO.startMonth} AND DATE_FORMAT(a.create_time, '%Y-%m') <= #{attendanceDTO.endMonth}
ORDER BY a.create_time DESC
